let slide=document.getElementById('slide-content'),audio=document.getElementById('audio-content'),audioUrl=audio.getAttribute('data-audio');function nextslide(){let a=slide.getAttribute('data-slide'),b=parseInt(slide.getAttribute('data-max'));if(a<b){let b=window.location.href+'slide/slide-'+(parseInt(a)+1)+'.jpg',c='https://archive.org/download/'+audioUrl+'/slide-'+(parseInt(a)+1)+'.mp3';slide.src=b,audio.src=c,audio.load(),audio.play(),slide.setAttribute("data-slide",parseInt(a)+1)}}function prevslide(){let a=slide.getAttribute('data-slide');if(a>1){let b=window.location.href+'slide/slide-'+(parseInt(a)-1)+'.jpg',c='https://archive.org/download/'+audioUrl+'/slide-'+(parseInt(a)-1)+'.mp3';slide.src=b,audio.src=c,audio.load(),audio.play(),slide.setAttribute("data-slide",parseInt(a)-1)}else{let b=window.location.href+'slide/slide-'+a+'.jpg',c='https://archive.org/download/'+audioUrl+'/slide-'+a+'.mp3';slide.src=b,audio.src=c,audio.load(),audio.play(),slide.setAttribute("data-slide","1")}}function pauseslide(){audio.pause()}function stopslide(){audio.pause(),audio.currentTime=0}function startslide(){audio.play()}document.getElementById("next-slide").addEventListener("click",function(){nextslide()}),document.getElementById("prev-slide").addEventListener("click",function(){prevslide()}),document.getElementById("stop-slide").addEventListener("click",function(){stopslide()}),document.getElementById("start-slide").addEventListener("click",function(){startslide()}),document.getElementById("pause-slide").addEventListener("click",function(){pauseslide()}),document.getElementById("start-presentation").addEventListener("click",function(){document.getElementById('slide-overlay').classList.add('hide'),document.getElementById('player').classList.add('active'),document.getElementById('slide-control').classList.add('show')}),audio.onended=function(){nextslide()}